function singularCategoryName(categoryName) {
return {
"Lamps": "Lamp",
"Chandeliers": "Chandelier",
"Ceiling Lights": "Ceiling Light",
"Wall Lights": "Wall Light"
}[categoryName] || categoryName.replace(/s$/, "");
}
function normalizeSearchText(value) {
return value.toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
}
function productCatalog() {
return Object.entries(catalogFiles).flatMap(([categoryName, files]) => {
const category = categories.find((item) => item.name === categoryName);
const folder = categoryName.replace(/\s+/g, "-");
const singular = singularCategoryName(categoryName);
return files.map((file, index) => {
const preview = category?.products[index];
const title = preview?.title || `${singular} Design ${index + 1}`;
return {
title,
category: categoryName,
image: `/product-assets/${folder}/${file}`,
href: `/products/${folder.toLowerCase()}`,
detail: preview?.detail || `Finest quality ${categoryName.toLowerCase()} for refined interiors.`,
price: index < 3 ? "$10" : "$120",
keywords: normalizeSearchText(`${title} ${categoryName} ${singular} design ${index + 1} lighting light ${file}`)
};
});
});
}
function searchProducts(query) {
const normalizedQuery = normalizeSearchText(query);
if (!normalizedQuery) return [];
const terms = normalizedQuery.split(" ").filter(Boolean);
return productCatalog().filter((product) => {
if (product.keywords.includes(normalizedQuery)) return true;
return terms.every((term) => product.keywords.includes(term));
});
}
function searchPageUrl(query) {
return `/search#q=${encodeURIComponent(query.trim())}`;
}
function submitSearch(query) {
const cleanQuery = query.trim();
if (!cleanQuery) return;
window.location.href = searchPageUrl(cleanQuery);
}
function suggestionItems(query, limit = 6) {
const categoryMatches = categories
.filter((category) => normalizeSearchText(category.name).includes(normalizeSearchText(query)))
.map((category) => ({
label: category.name,
meta: "Collection",
query: category.name
}));
const productMatches = searchProducts(query)
.slice(0, limit)
.map((product) => ({
label: product.title,
meta: product.category,
query: product.title
}));
const unique = [...categoryMatches, ...productMatches];
return unique.filter((item, index) => unique.findIndex((match) => match.label === item.label) === index).slice(0, limit);
}
function setupMobileMenu() {
if (!nav || !navLinks) return;
if (!navLinks.querySelector(".mobile-menu-search")) {
const search = document.createElement("form");
search.className = "mobile-menu-search";
search.setAttribute("role", "search");
search.innerHTML = `
<label class="sr-only" for="mobile-menu-search">Search lighting</label>
<input id="mobile-menu-search" type="search" placeholder="Search lighting">
<button type="submit" aria-label="Search">
<svg viewBox="0 0 24 24" aria-hidden="true"><path d="m21 21-4.35-4.35m1.35-5.15a6.5 6.5 0 1 1-13 0 6.5 6.5 0 0 1 13 0Z"/></svg>
</button>
<div class="search-suggestions mobile-search-suggestions" role="listbox"></div>
`;
navLinks.prepend(search);
search.addEventListener("submit", (event) => {
event.preventDefault();
submitSearch(search.querySelector("input").value);
});
}
document.querySelectorAll(".has-menu").forEach((item) => {
if (item.querySelector(".submenu-toggle")) return;
const toggle = document.createElement("button");
toggle.className = "submenu-toggle";
toggle.type = "button";
toggle.setAttribute("aria-label", "Open collections menu");
toggle.setAttribute("aria-expanded", "false");
item.querySelector(":scope > a")?.after(toggle);
toggle.addEventListener("click", (event) => {
event.preventDefault();
event.stopPropagation();
const isOpen = item.classList.toggle("submenu-open");
toggle.setAttribute("aria-expanded", String(isOpen));
});
});
const headerActions = nav.querySelector(".header-actions");
if (headerActions && !navLinks.querySelector(".mobile-menu-actions")) {
const mobileActions = headerActions.cloneNode(true);
mobileActions.classList.add("mobile-menu-actions");
mobileActions.setAttribute("aria-label", "Mobile store actions");
mobileActions.querySelector('[aria-label="Search"]')?.remove();
navLinks.append(mobileActions);
}
}
function productCard(product, category) {
return `
<article class="product-card swiper-slide reveal">
<img src="${product.image}" alt="${product.title} indoor lighting by Chic Lighting" loading="lazy">
<div class="product-body">
<div class="product-meta">
<span>${category.name}</span>
<span class="price">${product.price}</span>
</div>
<h3>${product.title}</h3>
<p>${product.detail}</p>
<div class="card-actions">
<a class="btn mini" href="/contact">Add to quote</a>
<a class="text-link" href="${category.href}">View collection</a>
</div>
</div>
</article>
`;
}
function renderProducts(activeCategory = "All") {
if (!productGrid) return;
const source = activeCategory === "All"
? categories.flatMap((category) => category.products.slice(0, 2).map((product) => ({ product, category })))
: categories
.filter((category) => category.name === activeCategory)
.flatMap((category) => category.products.map((product) => ({ product, category })));
productGrid.innerHTML = source.map(({ product, category }) => productCard(product, category)).join("");
observeReveals();
initProductSwiper();
}
function renderFilters() {
if (!filterBar) return;
const filters = ["All", ...categories.map((category) => category.name)];
filterBar.innerHTML = filters.map((name, index) => `
<button class="filter-button ${index === 0 ? "active" : ""}" type="button" role="tab" aria-selected="${index === 0}" data-category="${name}">
${name}
</button>
`).join("");
filterBar.addEventListener("click", (event) => {
const button = event.target.closest(".filter-button");
if (!button) return;
filterBar.querySelectorAll(".filter-button").forEach((item) => {
item.classList.toggle("active", item === button);
item.setAttribute("aria-selected", String(item === button));
});
renderProducts(button.dataset.category);
});
}
function initProductSwiper() {
if (!window.Swiper || !document.querySelector(".product-swiper")) return;
productSwiper?.destroy(true, true);
productSwiper = new Swiper(".product-swiper", {
slidesPerView: 1,
spaceBetween: 18,
grabCursor: true,
speed: 520,
keyboard: { enabled: true },
pagination: {
el: ".product-pagination",
clickable: true
},
navigation: {
nextEl: ".product-next",
prevEl: ".product-prev"
},
breakpoints: {
700: { slidesPerView: 2, spaceBetween: 20 },
1120: { slidesPerView: 3, spaceBetween: 22 }
}
});
}
